```typescript
// 実装開始: ProgressIndicator with WebSocket
interface TranscriptionProgress {
  transcriptionId: string;
  status: 'uploading' | 'transcribing' | 'completed' | 'error';
  progress: number;
  queuePosition?: number;
  estimatedTime?: number;
  currentStep?: string;
}

// WebSocket接続管理
const useTranscriptionProgress = (transcriptionId: string) => {
  const [progress, setProgress] = useState<TranscriptionProgress>();

  useEffect(() => {
    const ws = new WebSocket('/ws/transcribe-progress');
    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
      if (data.transcriptionId === transcriptionId) {
        setProgress(data);
      }
    };
    return () => ws.close();
  }, [transcriptionId]);

  return progress;
};
```

